URL: https://waba-v2.360dialog.io/messages
Sample Request Body:
{
  "messaging_product": "whatsapp",
  "recipient_type": "individual",
  "to": "<end_user_number>",
  "type": "template",
  "template": {
    "name": "<template_name>",
    "language": {
      "policy": "deterministic",
      "code": "<template_language>"
    },
    "components": [
      {
        "type": "button",
        "sub_type": "order_details",
        "index": 0,
        "parameters": [
          {
            "type": "action",
            "action": {
              "order_details": {
                "reference_id": "unique-reference-id",
                "type": "digital-goods",
                "payment_type": "br",
                "payment_settings": [
                  {
                    "type": "pix_dynamic_code",
                    "pix_dynamic_code": {
                      "code": "<pix_code_here>",
                      "merchant_name": "<company_name>",
                      "key": "39580525000189",
                      "key_type": "CNPJ"
                    }
                  }
                ],
                "currency": "BRL",
